    ('cat_chunky_crayons_and_big_paper', 10, 10, 'visible', true, true, 'Best for growing with them', 'Ooly Stars of the Sea Crayons', 'Ooly', NULL, 'https://www.ooly.com/products/stars-of-the-sea-crayons-set-of-6', NULL, '£5.95', NULL, NULL, 'Ooly — Ooly Stars of the Sea Crayons', 'Novelty star shape can be engaging for toddlers, encouraging creative exploration.', 'Novelty star shape can be engaging for toddlers, encouraging creative exploration.', NULL, 'borrow', NULL, NULL, NULL, NULL, 'emerging', ARRAY[]::text[], 'check_claim'),
    ('cat_feeling_faces_and_story_books', 1, 1, 'visible', true, false, 'Best for sharing big worries', 'Ruby’s Worry: A Big Bright Feelings Book', 'Tom Percival', 'Waterstones UK', 'https://www.waterstones.com/book/rubys-worry/tom-percival/tom-percival/9781408892152', NULL, '£6.99', 'in_stock', '3-7 years', 'A sensitive picture book about a little girl whose worry grows bigger and bigger until she learns to share it.', 'This book beautifully illustrates how worries can feel and grow, and the relief that comes from sharing them. It''s perfect for encouraging 31-33 month olds to articulate their own ''versions'' of anxieties, moving beyond simple identification to narrative expression. A useful option for any child beginning to express complex feelings.', 'The narrative arc of Ruby''s worry growing and then shrinking when shared directly supports the ''telling my version'' objective, showing the power of verbalizing feelings and experiences. This is a significant step up from simply pointing to feeling faces.', 'None.', 'buy', true, 'Thoughtful if age-fit and not already owned.', 'High chance the family owns a version already. Look for the stage shift: a version that adds clearer turns, richer pretend play, more control or easier setup rather than simply more of the same.', NULL, 'strong', ARRAY['https://www.waterstones.com/book/rubys-worry/tom-percival/tom-percival/9781408892152', 'https://www.amazon.co.uk/Rubys-Worry-Tom-Percival/dp/1408892154']::text[], 'none'),
    ('cat_feeling_faces_and_story_books', 2, 2, 'visible', true, true, 'Best for understanding big emotions', 'Ravi''s Roar: A Big Bright Feelings Book', 'Tom Percival', 'Waterstones UK', 'https://www.waterstones.com/book/ravis-roar/tom-percival/tom-percival/9781408892183', NULL, '£7.99', 'in_stock', '3-5 years', 'A vibrant story about a boy who turns into a tiger when he gets angry, learning to manage his temper.', 'This book is excellent for toddlers who are grappling with strong emotions like anger. It provides a relatable narrative for 31-33 month olds to understand and discuss their own ''roars'' and how to make amends, fostering emotional literacy and narrative skills.', 'Ravi''s transformation into a tiger vividly portrays intense anger, offering a concrete way for children to understand and articulate their own feelings. The resolution, where Ravi learns to make amends, directly supports the ''telling my version'' stage by modeling how to process and communicate after a big emotional outburst.', 'None.', 'buy', true, 'Thoughtful if age-fit and not already owned.', 'High chance the family owns a version already. Look for the stage shift: a version that adds clearer turns, richer pretend play, more control or easier setup rather than simply more of the same.', NULL, 'strong', ARRAY['https://www.waterstones.com/book/ravis-roar/tom-percival/tom-percival/9781408892183', 'https://www.amazon.co.uk/Ravis-Roar-Big-Bright-Feelings-Book/dp/1408892189']::text[], 'none'),
    ('cat_feeling_faces_and_story_books', 3, 3, 'visible', true, true, 'Best for exploring all feelings', 'The Great Big Book of Feelings', 'Mary Hoffman, Ros Asquith', 'Waterstones UK', 'https://www.waterstones.com/book/the-great-big-book-of-feelings/mary-hoffman/ros-asquith/9781847807588', NULL, '£9.99', 'in_stock', '4-9 years (BookTrust)', 'A comprehensive picture book exploring a wide range of emotions in various situations, encouraging discussion.', 'This book offers a broad and sensitive exploration of many feelings, making it ideal for 31-33 month olds to expand their emotional vocabulary and understand that all feelings are valid. The focus on discussion aligns perfectly with the ''telling my version'' stage.', 'By presenting a wide array of feelings in different contexts, this book helps children build a richer vocabulary for their emotional experiences. This supports the ''telling my version'' stage by giving them more tools to articulate their internal states and connect them to external events, moving beyond basic happy/sad to more nuanced expressions.', 'Age range starts at 4 years on BookTrust, but content is suitable for advanced 31-33 month olds with adult guidance.', 'buy', true, 'Thoughtful if age-fit and not already owned.', 'High chance the family owns a version already. Look for the stage shift: a version that adds clearer turns, richer pretend play, more control or easier setup rather than simply more of the same.', NULL, 'good', ARRAY['https://www.waterstones.com/book/the-great-big-book-of-feelings/mary-hoffman/ros-asquith/9781847807588', 'https://www.booktrust.org.uk/book-recommendations/bookfinder/the-great-big-book-of-feelings/']::text[], 'none'),
    ('cat_feeling_faces_and_story_books', 4, 4, 'visible', true, true, 'Best for talking about all feelings', 'In My Heart: A Book of Feelings', 'Jo Witek, Christine Roussey', 'Waterstones UK', 'https://www.waterstones.com/book/in-my-heart/jo-witek/christine-roussey/9781419713101', NULL, '£13.99', 'in_stock', 'From 3 years', 'An interactive book that explores various emotions like happiness, sadness, bravery, and anger through vibrant illustrations.', 'This book is a fantastic conversation starter for 31-33 month olds, allowing them to connect internal feelings with external expressions. The interactive elements encourage active participation in ''telling my version'' of how they feel.', 'The book''s structure, with different feelings represented by unique illustrations and descriptions, provides a scaffold for children to articulate their own emotional experiences. This directly supports the ''telling my version'' stage by offering a framework for expressing complex internal states in a relatable way.', 'None.', 'buy', true, 'Thoughtful if age-fit and not already owned.', 'High chance the family owns a version already. Look for the stage shift: a version that adds clearer turns, richer pretend play, more control or easier setup rather than simply more of the same.', NULL, 'good', ARRAY['https://www.waterstones.com/book/in-my-heart/jo-witek/christine-roussey/9781419713101', 'https://www.reddit.com/r/UKParenting/comments/10qpd6t/best_books_about_feelings_for_toddler/']::text[], 'none'),
    ('cat_feeling_faces_and_story_books', 5, 5, 'visible', true, true, 'Best for understanding worries', 'The Worrysaurus', 'Rachel Bright', 'Amazon UK', 'https://www.amazon.co.uk/Worrysaurus-Rachel-Bright/dp/1408356139', NULL, '£7.99', 'in_stock', 'No specific age, but described as for young children.', 'A little dinosaur learns to manage his anxious thoughts and enjoy a special picnic, with his mom''s help.', 'The Worrysaurus offers a gentle and relatable narrative for 31-33 month olds to explore feelings of anxiety and learn coping strategies. It encourages children to articulate their worries, aligning with the ''telling my version'' stage.', 'This book provides a clear storyline where a character experiences and overcomes worry, offering a model for children to understand and articulate their own anxieties. The emphasis on parental support in managing feelings reinforces the ''telling my version'' objective by showing how communication can help alleviate big emotions.', 'None.', 'buy', true, 'Thoughtful if age-fit and not already owned.', 'High chance the family owns a version already. Look for the stage shift: a version that adds clearer turns, richer pretend play, more control or easier setup rather than simply more of the same.', NULL, 'good', ARRAY['https://www.amazon.co.uk/Worrysaurus-Rachel-Bright/dp/1408356139', 'https://www.scottishbooktrust.com/book-lists/picture-books-to-help-children-explore-emotions']::text[], 'none'),
    ('cat_feeling_faces_and_story_books', 6, 6, 'visible', true, true, 'Best for budgets', 'Sometimes I Feel...', 'Sarah Maycock', NULL, 'https://www.waterstones.com/book/sometimes-i-feel/sarah-maycock/sarah-maycock/9781800781283', NULL, '£5.99', NULL, NULL, 'Sarah Maycock — Sometimes I Feel...', 'Explores feelings through animal similes and poetic prose, good for discussion.', 'Explores feelings through animal similes and poetic prose, good for discussion.', NULL, 'borrow', NULL, NULL, NULL, NULL, 'emerging', ARRAY[]::text[], 'check_claim'),
