    ('cat_safe_step_up_stool_or_learning_tower', 9, 5, 'visible', true, true, 'Best for gifting', 'Learning Tower, Green', 'GLTC', NULL, 'https://www.gltc.co.uk/products/learning-tower-green', NULL, '£85.00', NULL, NULL, 'GLTC — Learning Tower, Green', 'Same as the white version, good alternative color.', 'Same as the white version, good alternative color.', NULL, 'borrow', NULL, NULL, NULL, NULL, 'emerging', ARRAY[]::text[], 'check_claim'),
    ('cat_safe_step_up_stool_or_learning_tower', 10, 8, 'visible', true, true, 'Best for growing with them', 'The Classic - Convertible Learning Tower', 'The Learning Tower Company', NULL, 'https://learningtowers.co.uk/products/the-classic-convertible-learning-tower', NULL, '£154.99', NULL, NULL, 'The Learning Tower Company — The Classic - Convertible Learning Tower', 'Another good convertible option, slightly different design.', 'Another good convertible option, slightly different design.', NULL, 'borrow', NULL, NULL, NULL, NULL, 'emerging', ARRAY[]::text[], 'check_claim'),
    ('cat_soft_doll_or_teddy_care_play', 1, 1, 'visible', true, false, 'Best for interactive nurturing', 'Hannah Let''s Play! 36cm Interactive Doll', 'Baby Annabell', 'Amazon UK', 'https://www.amazon.co.uk/Baby-Annabell-Functions-Accessories-711002/dp/B0CWS6BSL5', NULL, '£25.00', 'in_stock', '1+', 'Interactive soft-bodied doll with baby sounds, drinking noises, giggles, and sleeping eyes. Includes bottle and dummy.', 'This interactive doll encourages rich nurturing play, with realistic sounds and accessories that allow toddlers to care for their ''baby''. It supports the shift towards more elaborate pretend worlds.', 'The interactive features like drinking sounds, giggles, and sleeping eyes directly support nurturing and care narratives, aligning with the stage shift towards comfort pretend play.', 'Requires 3 x AAA batteries. Not suitable for bath play.', 'buy', true, 'Thoughtful if age-fit and not already owned.', 'High chance the family owns a version already. Look for the stage shift: a version that adds clearer turns, richer pretend play, more control or easier setup rather than simply more of the same.', 'Warning: Not suitable for children under 3 years due to small parts (manufacturer''s warning on Amazon, despite 1+ age mark).', 'strong', ARRAY['https://www.amazon.co.uk/Baby-Annabell-Functions-Accessories-711002/dp/B0CWS6BSL5', 'https://www.mumsnet.com/swearsby/best-dolls']::text[], 'check_safety'),
    ('cat_soft_doll_or_teddy_care_play', 2, 2, 'visible', true, true, 'Best for first nurturing doll', 'My First Baby Girl Doll', 'John Lewis', 'John Lewis', 'https://www.johnlewis.com/john-lewis-my-first-baby-girl-doll/p5740683', NULL, '£12.50', 'in_stock', '2 years', 'Soft and squeezable baby doll with a onesie and hat, perfect for cuddles and imaginative play.', 'A classic, soft-bodied doll that''s ideal for introducing nurturing play. Its simplicity allows children to project their own caregiving scenarios, fitting the comfort pretend narrative.', 'Its soft body and simple design make it perfect for toddlers to hold and cuddle, fostering early nurturing instincts and care play.', 'No extra accessories included.', 'buy', true, 'Thoughtful if age-fit and not already owned.', 'High chance the family owns a version already. Look for the stage shift: a version that adds clearer turns, richer pretend play, more control or easier setup rather than simply more of the same.', 'Warning! Choking hazard - due to small parts that may cause a choking hazard, Warning! Not suitable for children under 2 years (despite age suitable from 2 years).', 'good', ARRAY['https://www.johnlewis.com/john-lewis-my-first-baby-girl-doll/p5740683', 'https://www.mumsnet.com/swearsby/best-dolls']::text[], 'check_safety'),
    ('cat_soft_doll_or_teddy_care_play', 3, 5, 'visible', true, true, 'Best for premium interactive care', 'Mon Grand Poupon Chérie', 'Corolle', 'Amazon UK', 'https://www.nytimes.com/wirecutter/out/link/76051/228653/4/236094?merchant=Amazon', NULL, '£73', 'in_stock', '2 years plus', 'Premium interactive doll with vanilla scent, 8 functions including giggles, kisses, burping, and sleeping sounds.', 'This premium doll offers a rich, interactive nurturing experience, with multiple sounds and accessories that deepen pretend play scenarios. It''s a great option for toddlers ready for more elaborate caregiving.', 'Its interactive functions and realistic sounds provide a rich platform for nurturing and care narratives, encouraging more elaborate pretend play beyond basic cuddling.', 'Higher price point. Requires batteries (not included).', 'buy', true, 'Thoughtful if age-fit and not already owned.', 'High chance the family owns a version already. Look for the stage shift: a version that adds clearer turns, richer pretend play, more control or easier setup rather than simply more of the same.', NULL, 'good', ARRAY['https://www.nytimes.com/wirecutter/reviews/best-dolls/', 'https://www.mumsnet.com/swearsby/best-dolls']::text[], 'check_price'),
    ('cat_soft_doll_or_teddy_care_play', 4, 4, 'visible', true, true, 'Best for realistic care play', 'Doll in Pink Bunny Outfit', 'Tiny Treasures', 'Argos', 'https://www.argos.co.uk/product/7469107', NULL, '£40', 'in_stock', '3 years plus', 'Realistic doll with weighted body, lifelike features, and a newborn scent. Comes with a birth certificate and hospital wristband.', 'This doll''s realistic features and weighted body encourage authentic care play, allowing toddlers to engage deeply in nurturing scenarios. It supports the comfort and care narratives of this stage.', 'The weighted body and realistic features provide an authentic caregiving experience, fostering nurturing play and emotional development.', 'Not interactive. Long hair may not appeal to all.', 'buy', true, 'Thoughtful if age-fit and not already owned.', 'High chance the family owns a version already. Look for the stage shift: a version that adds clearer turns, richer pretend play, more control or easier setup rather than simply more of the same.', NULL, 'strong', ARRAY['https://www.mumsnet.com/swearsby/best-dolls']::text[], 'check_url'),
    ('cat_soft_doll_or_teddy_care_play', 5, 11, 'visible', true, true, 'Best for accessory-led nurturing', 'Baby Doll Feed & Care Set', 'Ivy & Lily', 'Smyths Toys UK', 'https://www.smythstoys.com/uk/en-gb/brand/ivy-and-lily/ivy-and-lily-baby-doll-feed-and-care-set/p/248209', NULL, '£7.99', 'in_stock', '2 Years +', 'A set of pastel-colored accessories including a sippy cup, bowl, and spoon for feeding baby dolls.', 'This accessory set directly supports nurturing play, allowing toddlers to engage in feeding and caring for their dolls. It''s an excellent addition to any doll collection to enhance the ''pretend worlds bigger'' theme.', 'The focus on feeding and care accessories directly promotes nurturing play, aligning with the stage shift towards comfort and care narratives.', 'Doll sold separately.', 'buy', true, 'Thoughtful if age-fit and not already owned.', 'High chance the family owns a version already. Look for the stage shift: a version that adds clearer turns, richer pretend play, more control or easier setup rather than simply more of the same.', NULL, 'emerging', ARRAY['https://www.smythstoys.com/uk/en-gb/brand/ivy-and-lily/ivy-and-lily-baby-doll-feed-and-care-set/p/248209']::text[], 'check_url'),
    ('cat_soft_doll_or_teddy_care_play', 6, 3, 'visible', true, true, 'Best for budgets', 'Grace Rag Doll', 'Bigjigs Toys', NULL, 'https://www.amazon.co.uk/Bigjigs-Toys-Grace-Doll-Small/dp/B005F2LHK0', NULL, '£15.99', NULL, NULL, 'Bigjigs Toys — Grace Rag Doll', 'Super-soft traditional rag doll, good for cuddles and gentle imaginative play.', 'Super-soft traditional rag doll, good for cuddles and gentle imaginative play.', NULL, 'borrow', NULL, NULL, NULL, NULL, 'emerging', ARRAY[]::text[], 'check_claim'),
    ('cat_soft_doll_or_teddy_care_play', 7, 6, 'visible', true, true, 'Best for small spaces', 'Planet Rescuer', 'Lottie Doll', NULL, 'https://www.amazon.co.uk/Lottie-Doll-Planet-Rescuer-Eco-Friendly/dp/B08P268J1Y', NULL, '£20', NULL, NULL, 'Lottie Doll — Planet Rescuer', 'Focuses on inclusion and sustainability, offering a different dimension to imaginative play.', 'Focuses on inclusion and sustainability, offering a different dimension to imaginative play.', NULL, 'borrow', NULL, NULL, NULL, NULL, 'emerging', ARRAY[]::text[], 'check_claim'),
