JOIN public.pl_category_types ct
  ON ct.slug = r.source_category_entity_id
WHERE EXISTS (
  SELECT 1
  FROM public.pl_age_band_development_need_category_types abdnct
  WHERE abdnct.age_band_id = '31-33m'
    AND abdnct.category_type_id = ct.id
    AND abdnct.is_active = true
);

DO $$
DECLARE
  v_visible_count INTEGER;
  v_backup_count INTEGER;
BEGIN
  SELECT COUNT(*) INTO v_visible_count
  FROM public.pl_stage3_picks s
  JOIN public.pl_category_types ct ON ct.id = s.category_type_id
  WHERE s.age_band_id = '31-33m'
    AND ct.slug IN ('cat_big_soft_ball_for_turn_taking', 'cat_chunky_crayons_and_big_paper', 'cat_feeling_faces_and_story_books', 'cat_hoops_beanbags_and_jump_markers', 'cat_picture_books_with_little_stories', 'cat_pouring_cups_and_water_lab', 'cat_safe_step_up_stool_or_learning_tower', 'cat_soft_doll_or_teddy_care_play')
    AND s.status = 'visible'
    AND s.is_visible = true;

  IF v_visible_count <> 80 THEN
    RAISE EXCEPTION 'Expected 80 visible Stage 3 picks for 31-33m, got %', v_visible_count;
  END IF;

  SELECT COUNT(*) INTO v_backup_count
  FROM public.pl_stage3_picks s
  JOIN public.pl_category_types ct ON ct.id = s.category_type_id
  WHERE s.age_band_id = '31-33m'
    AND ct.slug IN ('cat_big_soft_ball_for_turn_taking', 'cat_chunky_crayons_and_big_paper', 'cat_feeling_faces_and_story_books', 'cat_hoops_beanbags_and_jump_markers', 'cat_picture_books_with_little_stories', 'cat_pouring_cups_and_water_lab', 'cat_safe_step_up_stool_or_learning_tower', 'cat_soft_doll_or_teddy_care_play')
    AND s.status = 'backup'
    AND s.is_visible = false;

  IF v_backup_count <> 37 THEN
    RAISE EXCEPTION 'Expected 37 backup Stage 3 picks for 31-33m, got %', v_backup_count;
  END IF;
END $$;

